export function Calendar({
  year,
  month,
  onPrevMonth,
  onNextMonth,
  onDateClick,
  getDayContent,
}) {
  const firstDay = new Date(year, month, 1).getDay()
  const daysInMonth = new Date(year, month + 1, 0).getDate()
  const totalCells = Math.ceil((firstDay + daysInMonth) / 7) * 7

  const monthName = new Intl.DateTimeFormat('he-IL', {
    month: 'long',
    year: 'numeric',
  }).format(new Date(year, month, 1))

  const dayHeaders = ['א', 'ב', 'ג', 'ד', 'ה', 'ו', 'ש']

  return (
    <div className="mb-4">
      {/* Month navigation */}
      <div className="flex items-center gap-2 mb-3 bg-card border border-border rounded-xl p-2 px-3">
        <Button
          variant="outline"
          size="sm"
          onClick={onPrevMonth}
          className="shrink-0 text-base"
        >
          →
        </Button>
        <div className="flex-1 text-center font-extrabold text-base">
          {monthName}
        </div>
        <Button
          variant="outline"
          size="sm"
          onClick={onNextMonth}
          className="shrink-0 text-base"
        >
          ←
        </Button>
      </div>

      {/* Day headers */}
      <div className="grid grid-cols-7 gap-[3px] mb-[3px]">
        {dayHeaders.map((day) => (
          <div
            key={day}
            className="text-center text-[11px] font-extrabold text-muted-foreground py-1"
          >
            {day}
          </div>
        ))}
      </div>

      {/* Calendar grid */}
      <div className="grid grid-cols-7 gap-[3px]">
        {Array.from({ length: totalCells }).map((_, i) => {
          const day = i - firstDay + 1
          const isValid = day >= 1 && day <= daysInMonth

          if (!isValid) {
            return <div key={i} />
          }

          const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`
          const content = getDayContent ? getDayContent(dateStr, day) : null

          return (
            <div
              key={i}
              onClick={() => onDateClick && onDateClick(dateStr)}
              className="min-h-[70px] p-1.5 rounded-lg cursor-pointer border border-border bg-card transition-opacity hover:opacity-80 flex flex-col"
            >
              <div className="text-xs font-semibold text-foreground mb-1">
                {day}
              </div>
              {content}
            </div>
          )
        })}
      </div>
    </div>
  )
}

